import React, { useState } from 'react';
import Payment from './Payment';

function Subscription({ onSubscribe, onClose }) {
  const [showPayment, setShowPayment] = useState(false);
  const [selectedPlan, setSelectedPlan] = useState(null);

  const plans = [
    { 
      id: 'monthly', 
      name: '💕 Mensuel', 
      price: '3,000 DA', 
      priceValue: 3000,
      features: ['💬 Messages illimités', '❤️ Likes illimités', '👑 Profil en vedette'], 
      color: '#FF69B4' 
    },
    { 
      id: 'yearly', 
      name: '💖 Annuel', 
      price: '15,000 DA', 
      priceValue: 15000,
      features: ['💬 Messages illimités', '❤️ Likes illimités', '👑 Profil en vedette', '🎁 Économie de 21,000 DA'], 
      color: '#FF1493', 
      popular: true 
    },
  ];

  const handlePlanSelect = (plan) => {
    setSelectedPlan(plan);
    setShowPayment(true);
  };

  const handlePaymentSuccess = () => {
    alert('🎉 Paiement réussi! Abonnement activé!');
    onSubscribe(selectedPlan);
    setShowPayment(false);
    onClose();
  };

  return (
    <>
      {showPayment ? (
        <Payment 
          plan={selectedPlan?.id}
          onSuccess={handlePaymentSuccess}
          onCancel={() => setShowPayment(false)}
        />
      ) : (
        <div style={styles.overlay}>
          <div style={styles.modal}>
            <button style={styles.closeBtn} onClick={onClose}>✕</button>
            <div style={styles.header}>
              <h1 style={styles.title}>💕 Chatalgerie Premium</h1>
              <p style={styles.subtitle}>Profitez de l'amour sans limites ❤️</p>
            </div>
            <div style={styles.plansContainer}>
              {plans.map((plan) => (
                <div key={plan.id} style={{
                  ...styles.planCard,
                  border: plan.popular ? '3px solid #FFD700' : '2px solid #e8e8e8',
                  boxShadow: plan.popular ? '0 8px 30px rgba(255,215,0,0.3)' : '0 4px 15px rgba(0,0,0,0.05)',
                }}>
                  {plan.popular && <div style={styles.popularBadge}>⭐ POPULAIRE</div>}
                  <h3 style={styles.planName}>{plan.name}</h3>
                  <p style={{...styles.planPrice, color: plan.color}}>{plan.price}</p>
                  <ul style={styles.planFeatures}>
                    {plan.features.map((f, i) => <li key={i} style={styles.featureItem}>✅ {f}</li>)}
                  </ul>
                  <button 
                    style={{...styles.subscribeBtn, backgroundColor: plan.color}} 
                    onClick={() => handlePlanSelect(plan)}
                  >
                    💳 Payer avec بريدي موب
                  </button>
                </div>
              ))}
            </div>
            <p style={styles.footer}>✨ Essaie gratuitement (3 messages), puis abonne-toi! ✨</p>
            <div style={styles.secureBadge}>🔒 Paiement sécurisé via بريدي موب</div>
          </div>
        </div>
      )}
    </>
  );
}

const styles = {
  overlay: {
    position: 'fixed',
    top: 0,
    left: 0,
    right: 0,
    bottom: 0,
    backgroundColor: 'rgba(0,0,0,0.7)',
    backdropFilter: 'blur(10px)',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    zIndex: 999,
    padding: '20px',
  },
  modal: {
    backgroundColor: 'white',
    borderRadius: '30px',
    padding: '40px',
    maxWidth: '900px',
    width: '100%',
    maxHeight: '90vh',
    overflowY: 'auto',
    position: 'relative',
    boxShadow: '0 30px 80px rgba(0,0,0,0.3)',
  },
  closeBtn: {
    position: 'absolute',
    top: '15px',
    right: '20px',
    background: 'none',
    border: 'none',
    fontSize: '30px',
    cursor: 'pointer',
    color: '#999',
  },
  header: {
    textAlign: 'center',
    marginBottom: '30px',
  },
  title: {
    fontSize: '2.5rem',
    fontWeight: 'bold',
    background: 'linear-gradient(45deg, #FF69B4, #4A90D9)',
    WebkitBackgroundClip: 'text',
    WebkitTextFillColor: 'transparent',
    marginBottom: '5px',
  },
  subtitle: {
    color: '#888',
    fontSize: '1.1rem',
    marginBottom: '10px',
  },
  plansContainer: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))',
    gap: '20px',
    marginBottom: '20px',
  },
  planCard: {
    backgroundColor: '#fafafa',
    borderRadius: '20px',
    padding: '25px 20px',
    textAlign: 'center',
    transition: 'transform 0.3s',
    position: 'relative',
  },
  popularBadge: {
    position: 'absolute',
    top: '-12px',
    left: '50%',
    transform: 'translateX(-50%)',
    backgroundColor: '#FFD700',
    color: '#333',
    padding: '5px 15px',
    borderRadius: '20px',
    fontSize: '0.8rem',
    fontWeight: 'bold',
  },
  planName: {
    fontSize: '1.3rem',
    fontWeight: 'bold',
    marginBottom: '10px',
    color: '#333',
  },
  planPrice: {
    fontSize: '2rem',
    fontWeight: 'bold',
    marginBottom: '15px',
  },
  planFeatures: {
    listStyle: 'none',
    padding: 0,
    marginBottom: '20px',
    textAlign: 'left',
  },
  featureItem: {
    padding: '8px 0',
    color: '#555',
    fontSize: '0.95rem',
    borderBottom: '1px solid #eee',
  },
  subscribeBtn: {
    width: '100%',
    padding: '12px',
    borderRadius: '12px',
    border: 'none',
    color: 'white',
    fontSize: '1rem',
    fontWeight: 'bold',
    cursor: 'pointer',
    transition: 'transform 0.2s',
  },
  footer: {
    textAlign: 'center',
    color: '#999',
    fontSize: '0.9rem',
    marginTop: '10px',
  },
  secureBadge: {
    textAlign: 'center',
    color: '#4CAF50',
    fontSize: '0.85rem',
    fontWeight: 'bold',
    marginTop: '10px',
  },
};

export default Subscription;
